#include <iostream>
#include <vector>
#include <map>

using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

void dfs(TreeNode* node, int depth, map<int, vector<int>> &levels)
{
    if (node == nullptr) return;
    levels[depth].push_back(node->val);
    dfs(node->left, depth + 1, levels);
    dfs(node->right, depth + 1, levels);
}

vector<vector<int>> levelOrder(TreeNode* root)
{
    map<int, vector<int>> levels;
    dfs(root, 0, levels);

    vector<vector<int>> result;
    for (auto &[depth, values] : levels) result.push_back(values);
    return result;
}

int main()
{
    TreeNode* root = new TreeNode(3);
    root->left = new TreeNode(9);
    root->right = new TreeNode(20);
    root->right->left = new TreeNode(15);
    root->right->right = new TreeNode(7);

    auto result = levelOrder(root);
    for (auto &level : result) { for (int v : level) cout << v << " "; cout << "| "; }

    return 0;
}

#include <iostream>
#include <vector>
#include <queue>

using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

vector<vector<int>> levelOrder(TreeNode* root)
{
    vector<vector<int>> result;
    if (root == nullptr) return result;

    queue<TreeNode*> q;
    q.push(root);

    while (!q.empty())
    {
        int levelSize = q.size();
        vector<int> level;

        for (int i = 0; i < levelSize; i++)
        {
            TreeNode* node = q.front(); q.pop();
            level.push_back(node->val);
            if (node->left) q.push(node->left);
            if (node->right) q.push(node->right);
        }

        result.push_back(level);
    }

    return result;
}

int main()
{
    TreeNode* root = new TreeNode(3);
    root->left = new TreeNode(9);
    root->right = new TreeNode(20);
    root->right->left = new TreeNode(15);
    root->right->right = new TreeNode(7);

    auto result = levelOrder(root);
    for (auto &level : result) { for (int v : level) cout << v << " "; cout << "| "; }

    return 0;
}

